public class DatabaseHelper extends SQLiteOpenHelper {
    private static final String DATABASE_NAME = "secure_user_data.db";
    private static final int DATABASE_VERSION = 1;
    
    public static final String TABLE_USER_PROFILE = "user_profiles";
    public static final String TABLE_PAYMENT_INFO = "payment_info";
    public static final String TABLE_SESSION_DATA = "session_data";
    
    public DatabaseHelper(Context context) {
        super(context, DATABASE_NAME, null, DATABASE_VERSION);
    }
    
    @Override
    public void onCreate(SQLiteDatabase db) {
        String createUserProfileTable = "CREATE TABLE " + TABLE_USER_PROFILE + " (" +
            "user_id TEXT PRIMARY KEY, " +
            "full_name TEXT, " +
            "email TEXT, " +
            "phone_number TEXT, " +
            "address TEXT)";
        
        String createPaymentInfoTable = "CREATE TABLE " + TABLE_PAYMENT_INFO + " (" +
            "id INTEGER PRIMARY KEY AUTOINCREMENT, " +
            "user_id TEXT, " +
            "card_number TEXT, " +
            "card_holder_name TEXT, " +
            "expiry_date TEXT, " +
            "cvv TEXT, " +
            "billing_address TEXT)";
        
        String createSessionDataTable = "CREATE TABLE " + TABLE_SESSION_DATA + " (" +
            "session_id TEXT PRIMARY KEY, " +
            "access_token TEXT, " +
            "refresh_token TEXT, " +
            "expiry_timestamp INTEGER)";
        
        db.execSQL(createUserProfileTable);
        db.execSQL(createPaymentInfoTable);
        db.execSQL(createSessionDataTable);
    }
    
    @Override
    public void onUpgrade(SQLiteDatabase db, int oldVersion, int newVersion) {
        db.execSQL("DROP TABLE IF EXISTS " + TABLE_USER_PROFILE);
        db.execSQL("DROP TABLE IF EXISTS " + TABLE_PAYMENT_INFO);
        db.execSQL("DROP TABLE IF EXISTS " + TABLE_SESSION_DATA);
        onCreate(db);
    }
}

